// LESSON: Reference Page 1 - Map-API.
// You will learn: Use key lookup, map views, computeIfAbsent, and merge updates.
class Prog2Reference430 {
  // EXEMPEL 1: put, get och containsKey arbetar med nycklar.
  static String capitals() {
    java.util.Map<String, String> capitals = new java.util.HashMap<String, String>();
    capitals.put("SE", "Stockholm");
    capitals.put("NO", "Oslo");
    return capitals.containsKey("SE") ? capitals.get("SE") : "missing";
  }
  // EXEMPEL 2: getOrDefault passar nar saknade nycklar ska starta pa noll.
  static java.util.Map<String, Integer> countWords(String[] words) {
    java.util.Map<String, Integer> counts = new java.util.HashMap<String, Integer>();
    for (String word : words) { counts.put(word, counts.getOrDefault(word, 0) + 1); }
    return counts;
  }
  // EXEMPEL 3: entrySet ger bade nyckel och varde i samma loop.
  static int totalPoints(java.util.Map<String, Integer> points) {
    int total = 0;
    for (java.util.Map.Entry<String, Integer> entry : points.entrySet()) { total += entry.getValue(); }
    return total;
  }
}
